  `id` int(11) NOT NULL,
  `accessory_id` int(11) NOT NULL,
  `door_type` enum('swing_single','swing_double','sliding_single','sliding_double','fixed','window','other') NOT NULL,
  `quantity` int(11) NOT NULL DEFAULT 1 COMMENT 'Số lượng sử dụng',
