--
-- Cấu trúc bảng cho bảng `aluminum_scraps`
--

CREATE TABLE `aluminum_scraps` (
  `id` int(11) NOT NULL,
  `project_id` int(11) DEFAULT NULL,
  `aluminum_system_id` int(11) NOT NULL,
  `profile_name` varchar(255) NOT NULL,
  `length_mm` int(11) NOT NULL,
  `weight_kg` decimal(8,3) DEFAULT NULL,
  `is_used` tinyint(1) DEFAULT 0,
  `used_in_project_id` int(11) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `status` varchar(16) DEFAULT 'available' COMMENT 'available|reserved|used|scrapped',
  `system_id` int(11) DEFAULT NULL COMMENT 'FK to aluminum_systems.id',
  `source_doc_id` int(11) DEFAULT NULL COMMENT 'FK to stock_documents.id',
  `source_project_id` int(11) DEFAULT NULL COMMENT 'FK to projects.id (sinh ra)',
  `used_project_id` int(11) DEFAULT NULL COMMENT 'FK to projects.id (sử dụng)',
  `used_doc_id` int(11) DEFAULT NULL COMMENT 'FK to stock_documents.id (sử dụng)',
  `used_at` datetime DEFAULT NULL COMMENT 'Thời điểm sử dụng',
  `used_by` int(11) DEFAULT NULL COMMENT 'User ID sử dụng',
  `note` text DEFAULT NULL COMMENT 'Ghi chú',
  `created_by` int(11) DEFAULT NULL COMMENT 'User ID tạo scrap',
  `scrap_code` varchar(50) DEFAULT NULL COMMENT 'Mã nhôm đề c (VD: DC-0001)'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

