--
-- Cấu trúc bảng cho bảng `audit_logs`
--

CREATE TABLE `audit_logs` (
  `id` bigint(20) NOT NULL,
  `event_code` varchar(100) NOT NULL COMMENT 'References event_types.event_code',
  `entity_type` varchar(50) NOT NULL COMMENT 'customer, project, quotation, etc.',
  `entity_id` int(11) NOT NULL,
  `entity_name` varchar(255) DEFAULT NULL COMMENT 'Name/Code for display',
  `actor_user_id` int(11) DEFAULT NULL COMMENT 'User who performed the action',
  `actor_name` varchar(100) DEFAULT NULL COMMENT 'User name for display',
  `action` varchar(50) NOT NULL COMMENT 'created, updated, deleted, etc.',
  `before_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'State before change' CHECK (json_valid(`before_data`)),
  `after_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'State after change' CHECK (json_valid(`after_data`)),
  `changed_fields` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'List of changed field names' CHECK (json_valid(`changed_fields`)),
  `reason` text DEFAULT NULL COMMENT 'Optional reason/note',
  `ip_address` varchar(45) DEFAULT NULL,
  `user_agent` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `bom_items`
--

