--
-- Cấu trúc bảng cho bảng `design_bom_lines`
--

CREATE TABLE `design_bom_lines` (
  `id` int(11) NOT NULL,
  `bom_id` int(11) NOT NULL,
  `source_unit_id` int(11) DEFAULT NULL,
  `material_type` enum('aluminum','glass','accessory','hardware','gasket','other') NOT NULL,
  `material_id` int(11) DEFAULT NULL,
  `material_code_snapshot` varchar(100) NOT NULL,
  `material_name_snapshot` varchar(255) NOT NULL,
  `uom_snapshot` varchar(20) NOT NULL,
  `qty` decimal(10,3) NOT NULL,
  `waste_factor` decimal(5,2) DEFAULT 0.00,
  `qty_with_waste` decimal(10,3) GENERATED ALWAYS AS (`qty` * (1 + `waste_factor` / 100)) STORED,
  `unit_price` decimal(15,2) DEFAULT 0.00,
  `line_total` decimal(15,2) GENERATED ALWAYS AS (`qty_with_waste` * `unit_price`) STORED,
  `vendor_id` int(11) DEFAULT NULL,
  `is_manual_override` tinyint(1) DEFAULT 0,
  `override_reason` text DEFAULT NULL,
  `override_by` int(11) DEFAULT NULL,
  `override_at` datetime DEFAULT NULL,
  `original_qty` decimal(10,3) DEFAULT NULL,
  `original_uom` varchar(20) DEFAULT NULL,
  `original_vendor_id` int(11) DEFAULT NULL,
  `original_waste_factor` decimal(5,2) DEFAULT NULL,
  `row_version` int(11) DEFAULT 1,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

