  `pr_id` int(11) NOT NULL,
  `bom_line_id` int(11) NOT NULL,
  `material_id` int(11) DEFAULT NULL,
  `material_code` varchar(100) NOT NULL,
  `material_name` varchar(255) NOT NULL,
  `uom` varchar(20) NOT NULL,
  `qty` decimal(10,3) NOT NULL,
  `needed_by_date` date DEFAULT NULL,
  `vendor_id` int(11) DEFAULT NULL,
  `snapshot_at` datetime DEFAULT current_timestamp(),
  `qty_on_hand` decimal(10,3) DEFAULT 0.000,
  `qty_reserved` decimal(10,3) DEFAULT 0.000,
  `qty_available` decimal(10,3) DEFAULT 0.000,
  `qty_on_order` decimal(10,3) DEFAULT 0.000,
  `qty_shortage` decimal(10,3) DEFAULT 0.000,
  `notes` text DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

