--
-- Cấu trúc bảng cho bảng `design_purchase_requests`
--

CREATE TABLE `design_purchase_requests` (
  `id` int(11) NOT NULL,
  `pr_code` varchar(50) NOT NULL,
  `project_id` int(11) NOT NULL,
  `design_revision_id` int(11) NOT NULL,
  `bom_id` int(11) NOT NULL,
  `revision_no_snapshot` int(11) DEFAULT NULL,
  `bom_version_snapshot` int(11) DEFAULT NULL,
  `status` enum('draft','submitted','approved','ordered','received','cancelled') DEFAULT 'draft',
  `pr_type` enum('full_bom','shortage_only','adjustment','supplement') DEFAULT 'shortage_only',
  `inventory_policy` enum('available','on_hand','net_shortage') DEFAULT 'available',
  `reason` text DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `submitted_by` int(11) DEFAULT NULL,
  `submitted_at` datetime DEFAULT NULL,
  `approved_by` int(11) DEFAULT NULL,
  `approved_at` datetime DEFAULT NULL,
  `rejected_by` int(11) DEFAULT NULL,
  `rejected_at` datetime DEFAULT NULL,
  `rejection_reason` text DEFAULT NULL,
  `row_version` int(11) DEFAULT 1,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `design_revisions`
--

CREATE TABLE `design_revisions` (
  `id` int(11) NOT NULL,
  `project_id` int(11) NOT NULL,
  `revision_no` int(11) DEFAULT 1,
  `status` enum('received','editing','locked','bom_created','pr_created') DEFAULT 'received',
  `is_active` tinyint(1) DEFAULT 1,
  `parent_revision_id` int(11) DEFAULT NULL,
  `locked_hash` varchar(64) DEFAULT NULL,
  `received_by` int(11) DEFAULT NULL,
  `received_at` datetime DEFAULT NULL,
  `received_channel` enum('email','zalo','direct','other') DEFAULT 'direct',
  `received_notes` text DEFAULT NULL,
  `input_checklist` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`input_checklist`)),
  `assigned_to` int(11) DEFAULT NULL,
  `deadline_at` datetime DEFAULT NULL,
  `started_editing_at` datetime DEFAULT NULL,
  `locked_by` int(11) DEFAULT NULL,
  `locked_at` datetime DEFAULT NULL,
  `locked_checklist` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`locked_checklist`)),
  `locked_file_id` int(11) DEFAULT NULL,
  `approved_by` int(11) DEFAULT NULL,
  `approved_at` datetime DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `row_version` int(11) DEFAULT 1,
  `created_by` int(11) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

