--
-- Cấu trúc bảng cho bảng `design_units`
--

CREATE TABLE `design_units` (
  `id` int(11) NOT NULL,
  `design_revision_id` int(11) NOT NULL,
  `unit_code` varchar(50) NOT NULL,
  `unit_type` enum('cua','vach','o_kinh','cua_nhom','cua_kinh','other') DEFAULT 'cua',
  `width` decimal(10,2) DEFAULT NULL,
  `height` decimal(10,2) DEFAULT NULL,
  `depth` decimal(10,2) DEFAULT NULL,
  `qty` int(11) DEFAULT 1,
  `area` decimal(10,4) GENERATED ALWAYS AS (`width` * `height` / 1000000) STORED,
  `profile_system_id` int(11) DEFAULT NULL,
  `profile_system` varchar(100) DEFAULT NULL,
  `profile_color` varchar(100) DEFAULT NULL,
  `glass_type_id` int(11) DEFAULT NULL,
  `glass_type` varchar(100) DEFAULT NULL,
  `glass_thickness` int(11) DEFAULT NULL,
  `hardware_set_id` int(11) DEFAULT NULL,
  `hardware_set` varchar(200) DEFAULT NULL,
  `num_panels` int(11) DEFAULT 1,
  `opening_direction` enum('left','right','both','fixed','sliding','other') DEFAULT 'fixed',
  `position_note` text DEFAULT NULL,
  `install_note` text DEFAULT NULL,
  `spec_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`spec_json`)),
  `row_version` int(11) DEFAULT 1,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `created_by` int(11) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

