--
-- Cấu trúc bảng cho bảng `financial_transaction_items`
--

CREATE TABLE `financial_transaction_items` (
  `id` int(11) NOT NULL,
  `transaction_id` int(11) NOT NULL COMMENT 'FK phiếu thu/chi',
  `item_type` enum('product','material','service','deposit','labor','transport','other') NOT NULL DEFAULT 'other' COMMENT 'Loại: sản phẩm, vật tư, dịch vụ, đặt cọc, nhân công, vận chuyển, khác',
  `item_name` varchar(255) NOT NULL COMMENT 'Tên sản phẩm/vật tư',
  `item_code` varchar(50) DEFAULT NULL COMMENT 'Mã vật tư (nếu có)',
  `specification` varchar(255) DEFAULT NULL COMMENT 'Quy cách: 1200x2400, màu xám...',
  `quantity` decimal(15,3) DEFAULT 1.000 COMMENT 'Số lượng',
  `unit` varchar(20) DEFAULT 'cái' COMMENT 'Đơn vị tính',
  `unit_price` decimal(15,2) DEFAULT 0.00 COMMENT 'Đơn giá (VNĐ)',
  `discount_percent` decimal(5,2) DEFAULT 0.00 COMMENT 'Giảm giá %',
  `amount` decimal(15,2) NOT NULL COMMENT 'Thành tiền = quantity * unit_price * (1 - discount%)',
  `source_type` varchar(50) DEFAULT NULL COMMENT 'quotation_item, stock_document_line, purchase_request_item, project_material',
  `source_id` int(11) DEFAULT NULL COMMENT 'ID nguồn',
  `note` text DEFAULT NULL COMMENT 'Ghi chú dòng',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

