-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `order_issues`
--

CREATE TABLE `order_issues` (
  `id` int(11) NOT NULL,
  `order_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `content` text DEFAULT NULL,
  `severity` enum('low','medium','high','critical') DEFAULT 'medium',
  `status` enum('open','in_progress','resolved','closed') DEFAULT 'open',
  `assigned_to` int(11) DEFAULT NULL,
  `resolved_by` int(11) DEFAULT NULL,
  `resolved_at` timestamp NULL DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `order_material_status`
--

CREATE TABLE `order_material_status` (
  `id` int(11) NOT NULL,
  `order_id` int(11) NOT NULL COMMENT 'FK to projects.id',
  `material_type` varchar(50) NOT NULL,
  `status` varchar(50) DEFAULT 'NONE',
  `plan_date` date DEFAULT NULL,
  `actual_date` date DEFAULT NULL,
  `source_type` enum('manual','stock_document','purchase_request') DEFAULT 'manual',
  `source_id` int(11) DEFAULT NULL,
  `note` text DEFAULT NULL,
  `featured_products` varchar(500) DEFAULT NULL COMMENT 'Sản phẩm đặc chưng cho loại vật tư này',
  `quantity` decimal(15,3) DEFAULT NULL COMMENT 'Khối lượng vật tư (kg hoặc đơn vị phù hợp)',
  `updated_by` int(11) DEFAULT NULL,
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

