--
-- Cấu trúc bảng cho bảng `product_manufacturing`
--

CREATE TABLE `product_manufacturing` (
  `id` int(11) NOT NULL,
  `project_id` int(11) NOT NULL,
  `product_id` varchar(50) NOT NULL,
  `design_id` int(11) DEFAULT NULL,
  `status` enum('not_assigned','missing_materials','ready','manufacturing','completed') NOT NULL DEFAULT 'not_assigned',
  `last_status` enum('not_assigned','missing_materials','ready','manufacturing','completed') DEFAULT NULL COMMENT 'Previous status for audit',
  `status_updated_at` datetime DEFAULT NULL COMMENT 'When status last changed',
  `materials_required_count` int(11) DEFAULT 0 COMMENT 'Total materials needed',
  `materials_exported_count` int(11) DEFAULT 0 COMMENT 'Materials exported from warehouse',
  `materials_percent` int(11) DEFAULT 0 COMMENT 'Cached percentage for performance',
  `started_at` datetime DEFAULT NULL COMMENT 'When manufacturing started',
  `completed_at` datetime DEFAULT NULL COMMENT 'When product completed',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Manufacturing status: not_assigned → missing_materials → ready → manufacturing → completed';

