--
-- Cấu trúc bảng cho bảng `product_template_accessories`
--

CREATE TABLE `product_template_accessories` (
  `id` int(11) NOT NULL,
  `product_template_id` int(11) NOT NULL COMMENT 'FK to product_templates',
  `accessory_id` int(11) NOT NULL COMMENT 'FK to accessories',
  `quantity_override` decimal(10,2) DEFAULT NULL COMMENT 'NULL = dùng default từ accessory_applications',
  `is_excluded` tinyint(1) DEFAULT 0 COMMENT 'True = không dùng phụ kiện này cho template',
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Override phụ kiện cho template cụ thể';

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `projects`
--

CREATE TABLE `projects` (
  `id` int(11) NOT NULL,
  `project_code` varchar(50) NOT NULL,
  `project_name` varchar(255) NOT NULL,
  `customer_id` int(11) NOT NULL,
  `start_date` date DEFAULT NULL,
  `deadline` date DEFAULT NULL,
  `status` enum('new','quotation_pending','designing','bom_extraction','in_production','installation','handover','completed','paused','cancelled') DEFAULT 'new',
  `progress_percent` int(11) DEFAULT 0,
  `quote_locked` tinyint(1) DEFAULT 0,
  `contract_locked` tinyint(1) DEFAULT 0,
  `total_value` decimal(15,2) DEFAULT 0.00,
  `material_cost` decimal(15,2) DEFAULT 0.00 COMMENT 'Tổng chi phí vật tư',
  `assigned_to` int(11) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `handover_date` date DEFAULT NULL,
  `handover_status` varchar(32) DEFAULT 'pending',
  `handover_notes` text DEFAULT NULL,
  `moved_to_installation_at` datetime DEFAULT NULL,
  `handover_by` varchar(255) DEFAULT NULL,
  `received_by` varchar(255) DEFAULT NULL,
  `receiver_phone` varchar(50) DEFAULT NULL,
  `handover_person` varchar(255) DEFAULT NULL,
  `receiver_name` varchar(255) DEFAULT NULL,
  `handover_photos` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`handover_photos`)),
  `completed_at` datetime DEFAULT NULL,
  `installation_step` enum('not_started','started','in_progress','completed') DEFAULT 'not_started',
  `installation_date` datetime DEFAULT NULL,
  `installer_name` varchar(255) DEFAULT NULL,
  `installation_notes` text DEFAULT NULL,
  `installation_photos` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`installation_photos`)),
  `production_step` enum('preparing','manufacturing','completed') DEFAULT 'preparing',
  `production_started_at` datetime DEFAULT NULL,
  `agency_id` int(11) DEFAULT NULL,
  `operation_status` tinyint(4) DEFAULT 1,
  `operation_notes` text DEFAULT NULL,
  `operation_updated_at` datetime DEFAULT NULL,
  `construction_province` varchar(100) DEFAULT NULL COMMENT 'Tỉnh/Thành phố công trình',
  `construction_district` varchar(100) DEFAULT NULL COMMENT 'Quận/Huyện công trình',
  `construction_address` text DEFAULT NULL COMMENT 'Địa chỉ chi tiết công trình',
  `fix_compatible` text DEFAULT NULL,
  `manual_weight` decimal(15,3) DEFAULT NULL COMMENT 'Khối lượng nhôm thủ công (kg) - ghi đè khối lượng tính từ BOM',
  `excel_note` text DEFAULT NULL,
  `production_notes` text DEFAULT NULL,
  `production_progress` int(11) DEFAULT 0,
  `production_photos` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`production_photos`)),
  `cancelled_at` datetime DEFAULT NULL,
  `cancel_reason` text DEFAULT NULL,
  `previous_status` varchar(50) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
