--
-- Cấu trúc bảng cho bảng `project_material_status`
--

CREATE TABLE `project_material_status` (
  `id` int(11) NOT NULL,
  `project_id` int(11) NOT NULL,
  `material_type` enum('glass','aluminum','accessory','auxiliary') NOT NULL,
  `status` enum('ok','waiting','missing','ordered','arrived') DEFAULT 'missing',
  `order_date` date DEFAULT NULL,
  `expected_date` date DEFAULT NULL,
  `actual_date` date DEFAULT NULL,
  `quantity` decimal(10,2) DEFAULT NULL,
  `quantity_arrived` decimal(10,2) DEFAULT NULL,
  `supplier` varchar(255) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `confirmed_by` int(11) DEFAULT NULL,
  `confirmed_at` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

