--
-- Cấu trúc bảng cho bảng `purchase_requests`
--

CREATE TABLE `purchase_requests` (
  `id` int(11) NOT NULL,
  `request_code` varchar(50) NOT NULL COMMENT 'Mã phiếu yêu cầu (tự động tạo)',
  `project_id` int(11) DEFAULT NULL COMMENT 'ID dự án (nếu có)',
  `project_name` varchar(255) DEFAULT NULL COMMENT 'Tên dự án',
  `order_code` varchar(100) DEFAULT NULL COMMENT 'Mã đơn hàng',
  `product_type` varchar(100) DEFAULT NULL COMMENT 'Chủng loại',
  `color` varchar(100) DEFAULT NULL COMMENT 'Màu sắc',
  `delivery_address` text DEFAULT NULL COMMENT 'Địa chỉ giao hàng',
  `created_date` date DEFAULT NULL COMMENT 'Ngày tạo',
  `required_date` date DEFAULT NULL COMMENT 'Ngày cần vật tư về',
  `nhom_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Dữ liệu nhôm (JSON)' CHECK (json_valid(`nhom_data`)),
  `vattu_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Dữ liệu vật tư phụ (JSON)' CHECK (json_valid(`vattu_data`)),
  `phukien_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Dữ liệu phụ kiện (JSON)' CHECK (json_valid(`phukien_data`)),
  `kinh_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Dữ liệu kính (JSON)' CHECK (json_valid(`kinh_data`)),
  `status` enum('draft','submitted','approved','rejected','completed') DEFAULT 'draft' COMMENT 'Trạng thái phiếu',
  `notes` text DEFAULT NULL COMMENT 'Ghi chú',
  `created_by` int(11) DEFAULT NULL COMMENT 'Người tạo',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Phiếu yêu cầu vật tư';

