--
-- Cấu trúc bảng cho bảng `stock_document_lines`
--

CREATE TABLE `stock_document_lines` (
  `id` int(11) NOT NULL,
  `document_id` int(11) NOT NULL,
  `item_type` enum('accessory','aluminum','glass','other') NOT NULL,
  `item_id` int(11) NOT NULL,
  `item_code` varchar(50) DEFAULT NULL,
  `item_name` varchar(255) DEFAULT NULL,
  `qty` decimal(15,3) NOT NULL,
  `unit` varchar(20) DEFAULT 'cái',
  `unit_price` decimal(15,2) DEFAULT 0.00,
  `line_total` decimal(15,2) DEFAULT 0.00,
  `qty_system` decimal(15,3) DEFAULT NULL,
  `qty_actual` decimal(15,3) DEFAULT NULL,
  `qty_diff` decimal(15,3) DEFAULT NULL,
  `note` text DEFAULT NULL,
  `project_id` int(11) DEFAULT NULL COMMENT 'Dự án (cho phiếu xuất)',
  `request_line_id` int(11) DEFAULT NULL COMMENT 'FK yêu cầu xuất (nếu có)',
  `system_id` int(11) DEFAULT NULL COMMENT 'FK aluminum_systems.id',
  `need_cm` int(11) DEFAULT NULL COMMENT 'Aluminum: cm cần dùng',
  `bars_deducted` int(11) DEFAULT NULL COMMENT 'Aluminum: số cây đã trừ',
  `scrap_created_cm` int(11) DEFAULT NULL COMMENT 'Aluminum: cm thừa đã sinh',
  `scrap_used_cm` int(11) DEFAULT NULL COMMENT 'Aluminum: cm thừa đã sử dụng',
  `use_scrap` tinyint(1) DEFAULT 0 COMMENT 'Ưu tiên dùng nhôm thừa',
  `meters_used` decimal(10,2) DEFAULT NULL COMMENT 'Mét sử dụng (chỉ áp dụng cho nhôm)',
  `length_per_bar_m` decimal(10,2) DEFAULT NULL COMMENT 'Dài/cây snapshot từ kho nhôm (m)',
  `meters_leftover` decimal(10,2) DEFAULT NULL COMMENT 'Mét thừa = qty * length_per_bar_m - meters_used'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

