--
-- Cấu trúc bảng cho bảng `stock_ledger`
--

CREATE TABLE `stock_ledger` (
  `id` int(11) NOT NULL,
  `document_id` int(11) NOT NULL,
  `document_line_id` int(11) DEFAULT NULL,
  `warehouse_id` int(11) DEFAULT 1,
  `item_type` enum('accessory','aluminum','glass','other') NOT NULL,
  `item_id` int(11) NOT NULL,
  `qty_in` decimal(15,3) DEFAULT 0.000,
  `qty_out` decimal(15,3) DEFAULT 0.000,
  `balance_after` decimal(15,3) NOT NULL,
  `transaction_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `user_id` int(11) DEFAULT NULL,
  `note` text DEFAULT NULL,
  `meta_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Metadata for special calculations' CHECK (json_valid(`meta_json`))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

