--
-- Cấu trúc bảng cho bảng `user_notification_settings`
--

CREATE TABLE `user_notification_settings` (
  `id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `channel_in_app` tinyint(1) DEFAULT 1,
  `channel_email` tinyint(1) DEFAULT 0,
  `channel_telegram` tinyint(1) DEFAULT 0,
  `mute_modules` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'List of muted modules' CHECK (json_valid(`mute_modules`)),
  `quiet_hours_start` time DEFAULT NULL COMMENT 'Start of quiet hours',
  `quiet_hours_end` time DEFAULT NULL COMMENT 'End of quiet hours',
  `email_digest` enum('realtime','daily','weekly','none') DEFAULT 'realtime',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
