--
-- Cấu trúc cho view `v_stock_onhand`
--
DROP TABLE IF EXISTS `v_stock_onhand`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_stock_onhand`  AS SELECT `l`.`warehouse_id` AS `warehouse_id`, `l`.`item_type` AS `item_type`, `l`.`item_id` AS `item_id`, (select `l2`.`balance_after` from `stock_ledger` `l2` where `l2`.`warehouse_id` = `l`.`warehouse_id` and `l2`.`item_type` = `l`.`item_type` and `l2`.`item_id` = `l`.`item_id` order by `l2`.`transaction_at` desc,`l2`.`id` desc limit 1) AS `qty_on_hand`, 0 AS `qty_reserved`, (select `l2`.`balance_after` from `stock_ledger` `l2` where `l2`.`warehouse_id` = `l`.`warehouse_id` and `l2`.`item_type` = `l`.`item_type` and `l2`.`item_id` = `l`.`item_id` order by `l2`.`transaction_at` desc,`l2`.`id` desc limit 1) AS `qty_available` FROM `stock_ledger` AS `l` GROUP BY `l`.`warehouse_id`, `l`.`item_type`, `l`.`item_id` ;

